import{_ as r,o as a,c as e,a3 as t}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"29. Hours Of Work Fractional Doctors","description":"","frontmatter":{"title":"29. Hours Of Work Fractional Doctors","eba":"Medical Specialists 2022-2026","topics":["hours"]},"headers":[],"relativePath":"ebas/medical-specialists/hours-of-work/29-hours-of-work-fractional-doctors.md","filePath":"ebas/medical-specialists/hours-of-work/29-hours-of-work-fractional-doctors.md"}'),s={name:"ebas/medical-specialists/hours-of-work/29-hours-of-work-fractional-doctors.md"};function i(n,o,c,l,h,d){return a(),e("div",null,[...o[0]||(o[0]=[t('<h1 id="_29-hours-of-work-fractional-doctors" tabindex="-1">29. Hours Of Work Fractional Doctors <a class="header-anchor" href="#_29-hours-of-work-fractional-doctors" aria-label="Permalink to &quot;29. Hours Of Work Fractional Doctors&quot;">​</a></h1><p><strong>29.1</strong> Subject to this clause, the ordinary hours of work for a Fractional Doctor will be in accordance with their fractional allocation of hours as agreed between the Health Service and the Doctor.</p><p><strong>29.2</strong> The maximum number of ordinary hours of work for a Fractional Doctor is 35 hours per week.</p><p><strong>29.3</strong> At the time of engagement, the Health Service and a Fractional Doctor will agree in writing on the following matters:</p><p><strong>(a)</strong> a regular pattern of work, specifying at least the hours worked each day; and</p><p><strong>(b)</strong> which days of the week the Fractional Doctor will work.</p><p><strong>29.4</strong> Any agreed variation to the regular pattern of work will be recorded in writing.</p><p><strong>29.5</strong> Work required by the Health Service to be performed by a Fractional Specialist in excess of their Fractional Allocation (as determined pursuant to <a href="/eba/ebas/medical-specialists/hours-of-work/30-fractional-allocation-fractional-doctors.html">clause 30</a>) will be compensated by:</p><p><strong>(a)</strong> payment at no less than the applicable Fractional hourly rate prescribed for ordinary work at <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a>; or</p><p><strong>(b)</strong> in accordance with an agreed local arrangement.</p><p>This excludes work performed on a fee for service or scheduled fee basis (including, by way of example only, the Commonwealth Medical Benefits Schedule) (CMBS)) or where the Fractional Doctor is compensated in a way other than salary.</p><p>Plain language terms: ordinary hours.</p>',12)])])}const u=r(s,[["render",i]]);export{f as __pageData,u as default};
